import React from 'react';
import '../../styles/Windows/StyleAddTaskWindow.css';
import '../../styles/CommonUI.css';
import '../../styles/Windows/StyleTaskDescriptionModal.css';

export default function TaskDescriptionModal({ task, isOpen, onClose }) {
    if (!isOpen || !task) return null;

    return (
        <div className="modal-overlay" onClick={onClose}>
            {/* Добавляем класс custom-modal-adaptive для адаптивности */}
            <div className="modal-content glass-panel task-desc-panel custom-modal-adaptive" onClick={(e) => e.stopPropagation()}>

                <button className="common-close-btn" onClick={onClose}>
                    <img src="https://img.icons8.com/?size=96&id=X3PpUHcCmmeD&format=png" alt="Close" />
                </button>

                <h2 className="desc-title">{task.title}</h2>

                {/* Добавляем класс custom-scrollbar для скролла внутри описания */}
                <div className="task-full-desc custom-scrollbar">
                    {task.description ? task.description : <em style={{opacity: 0.5}}>Описание отсутствует</em>}
                </div>

                <div className="modal-buttons">
                    <button className="btn-save" onClick={onClose}>
                        <span className="btn-text">Закрыть</span>
                        <img src="https://img.icons8.com/?size=96&id=GqJpEbXPcmLg&format=png" alt="Check" className="btn-icon" />
                        <div className="btn-bg-slide"></div>
                    </button>
                </div>
            </div>
        </div>
    );
}
